import mujoco, numpy as np, time
base = open('model_ref.xml').read()
def build(opt_xml):
    xml = base.replace('<size memory', opt_xml+'\n  <size memory')
    return mujoco.MjModel.from_xml_string(xml)
def run(m, seed):
    d=mujoco.MjData(m); n=int(2.0/m.opt.timestep)
    rng=np.random.default_rng(seed); d.qpos+=rng.normal(0,0.01,size=d.qpos.shape)
    mujoco.mj_forward(m,d)
    for _ in range(n): mujoco.mj_step(m,d)
    return d.qpos.copy()
def timeit(m):
    ts=[]
    for s in range(8):
        t0=time.perf_counter(); run(m,s); ts.append(time.perf_counter()-t0)
    return np.mean(ts)
ref=build('')
qref=run(ref,3)
configs={
 'ref':'',
 'nocon':'<option><flag contact=\"disable\"/></option>',
 'cg':'<option solver=\"CG\"/>',
 'pgs':'<option solver=\"PGS\"/>',
 'jacsparse':'<option jacobian=\"sparse\"/>',
 'jacdense':'<option jacobian=\"dense\"/>',
 'iter1':'<option iterations=\"1\" ls_iterations=\"5\"/>',
}
for name,o in configs.items():
    m=build(o); q=run(m,3); d=np.abs(q-qref).max(); t=timeit(m)
    print(f'{name:12s} t={t:.4f} statediff={d:.2e}')
"

