import mujoco, numpy as np, time
base = open('model_ref.xml').read()
def build(opt_xml):
    return mujoco.MjModel.from_xml_string(base.replace('<size memory', opt_xml+'\n  <size memory'))
def run(m, seed):
    d=mujoco.MjData(m); n=int(2.0/m.opt.timestep)
    rng=np.random.default_rng(seed); d.qpos+=rng.normal(0,0.01,size=d.qpos.shape)
    mujoco.mj_forward(m,d)
    for _ in range(n): mujoco.mj_step(m,d)
    fp=mujoco.mjtState.mjSTATE_FULLPHYSICS
    s=np.zeros(mujoco.mj_stateSize(m,fp)); mujoco.mj_getState(m,d,s,fp); return s
def timeit(m,k=8):
    ts=[]
    for s in range(k):
        t0=time.perf_counter(); run(m,s+100); ts.append(time.perf_counter()-t0)
    return np.median(ts)
ref=build('')
configs={
 'pgs':'<option solver=\"PGS\"><flag contact=\"disable\"/></option>',
 'pgs_dense':'<option solver=\"PGS\" jacobian=\"dense\"><flag contact=\"disable\"/></option>',
 'cg_dense':'<option solver=\"CG\" jacobian=\"dense\"><flag contact=\"disable\"/></option>',
 'pgs_dense_i':'<option solver=\"PGS\" jacobian=\"dense\" iterations=\"100\"><flag contact=\"disable\"/></option>',
}
tref=timeit(ref)
print('tref',round(tref,4))
for name,o in configs.items():
    m=build(o)
    maxd=max(np.abs(run(m,s)-run(ref,s)).max() for s in range(15))
    t=timeit(m)
    print(f'{name:14s} t={t:.4f} pctg={t/tref:.2f} maxstatediff={maxd:.2e}')
"

